import React, { useState, useEffect, useRef, useCallback } from "react";
import { useParams, useNavigate } from "react-router-dom";
import { useApp } from "../App";
import { haptic } from "../lib/telegram";

const WS_BASE = (process.env.REACT_APP_API_URL || "http://localhost:8000")
  .replace(/^http/, "ws");

export default function GamePage() {
  const { code } = useParams();
  const { user, setUser } = useApp();
  const navigate = useNavigate();
  const [game, setGame] = useState(null);
  const [copied, setCopied] = useState(false);
  const [status, setStatus] = useState("connecting");
  const wsRef = useRef(null);
  const pingRef = useRef(null);

  const connect = useCallback(() => {
    const ws = new WebSocket(`${WS_BASE}/ws/game/${code}/${user.id}`);
    wsRef.current = ws;

    ws.onopen = () => {
      setStatus("connected");
      pingRef.current = setInterval(() => {
        if (ws.readyState === WebSocket.OPEN) ws.send(JSON.stringify({ type: "ping" }));
      }, 20000);
    };

    ws.onmessage = (e) => {
      const msg = JSON.parse(e.data);
      if (msg.type === "state") setGame(msg.game);
      if (msg.type === "error") setStatus("error_" + msg.message);
    };

    ws.onclose = () => {
      clearInterval(pingRef.current);
      setStatus("disconnected");
      setTimeout(connect, 3000);
    };

    ws.onerror = () => ws.close();
  }, [code, user.id]);

  useEffect(() => {
    connect();
    return () => {
      clearInterval(pingRef.current);
      wsRef.current?.close();
    };
  }, [connect]);

  function makeMove(index) {
    if (!game || game.status !== "playing") return;
    if (game.turn !== user.id) return;
    if (game.board[index] !== null) return;
    haptic.impact("light");
    wsRef.current?.send(JSON.stringify({ type: "move", index }));
  }

  function copyCode() {
    navigator.clipboard?.writeText(code);
    setCopied(true);
    haptic.notification("success");
    setTimeout(() => setCopied(false), 2000);
  }

  if (!game) return (
    <div className="loader" style={{ minHeight: "100vh", flexDirection: "column", gap: 16 }}>
      <div className="spinner" />
      <p style={{ color: "var(--text2)", fontFamily: "Unbounded", fontSize: 12 }}>Подключаемся...</p>
    </div>
  );

  const myPlayer = game.players.find(p => p.user_id === user.id);
  const mySymbol = myPlayer?.symbol;
  const isMyTurn = game.turn === user.id && game.status === "playing";
  const creator = game.players[0];
  const skins = game.skins[creator.user_id] || { x: "✕", o: "○" };

  const getStatusText = () => {
    if (game.status === "waiting") return "Ожидаем соперника...";
    if (game.status === "finished") {
      if (!game.winner_id) return "🤝 Ничья!";
      if (game.winner_id === user.id) return "🏆 Ты победил!";
      if (game.winner_id === "AI_BOT") return "🤖 Бот победил";
      return "😔 Ты проиграл";
    }
    if (isMyTurn) return "✨ Твой ход!";
    return "⏳ Ход соперника";
  };

  const statusColor = () => {
    if (game.status === "finished") {
      if (!game.winner_id) return "var(--gold)";
      if (game.winner_id === user.id) return "var(--green)";
      return "var(--red)";
    }
    if (isMyTurn) return "var(--accent2)";
    return "var(--text2)";
  };

  return (
    <div style={{
      minHeight: "100vh", display: "flex", flexDirection: "column",
      padding: 16, paddingTop: 24, paddingBottom: 24
    }}>
      {/* Header */}
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 24 }}>
        <button className="btn btn-secondary btn-sm" onClick={() => navigate("/")}>← Выйти</button>
        <div style={{ textAlign: "center" }}>
          <div style={{ fontFamily: "Unbounded", fontSize: 13, color: "var(--text2)" }}>КОД ИГРЫ</div>
          <div style={{ fontFamily: "Unbounded", fontSize: 20, fontWeight: 700, letterSpacing: 3 }}>{code}</div>
        </div>
        <button className="btn btn-secondary btn-sm" onClick={copyCode}>
          {copied ? "✓" : "📋"}
        </button>
      </div>

      {/* Status */}
      <div style={{
        textAlign: "center", marginBottom: 24,
        fontFamily: "Unbounded", fontSize: 16, fontWeight: 700,
        color: statusColor(),
        animation: game.status === "finished" ? "winPulse 1s ease infinite" : undefined
      }}>
        {getStatusText()}
      </div>

      {/* Players */}
      <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 24, gap: 8 }}>
        {game.players.map((p, i) => {
          const isMe = p.user_id === user.id;
          const isBot = p.user_id === "AI_BOT";
          const symbol = p.symbol === "X" ? skins.x : skins.o;
          const isActive = game.turn === p.user_id && game.status === "playing";
          return (
            <div key={i} style={{
              flex: 1, padding: "12px 16px",
              background: isActive ? "rgba(124,92,252,0.15)" : "var(--card)",
              border: `1.5px solid ${isActive ? "var(--accent)" : "var(--border)"}`,
              borderRadius: "var(--radius)", textAlign: "center",
              transition: "all 0.3s"
            }}>
              <div style={{ fontSize: 24, marginBottom: 4 }}>{symbol}</div>
              <div style={{ fontSize: 12, fontWeight: 600, color: isMe ? "var(--accent3)" : "var(--text2)" }}>
                {isBot ? "🤖 Бот" : isMe ? "Ты" : "Соперник"}
              </div>
              {isActive && <div style={{ fontSize: 10, color: "var(--accent)", marginTop: 2 }}>● ходит</div>}
            </div>
          );
        })}
      </div>

      {/* Bet info */}
      {game.bet > 0 && (
        <div style={{
          textAlign: "center", marginBottom: 16, padding: "8px 16px",
          background: "rgba(245,158,11,0.1)", border: "1px solid rgba(245,158,11,0.3)",
          borderRadius: 10, color: "var(--gold)", fontSize: 13, fontWeight: 600
        }}>
          💰 Ставка: {game.bet} монет · Банк: {game.bet * game.players.length}
        </div>
      )}

      {/* Board */}
      <div style={{
        display: "grid", gridTemplateColumns: "repeat(3, 1fr)",
        gap: 10, maxWidth: 360, margin: "0 auto", width: "100%", flex: 1,
        alignContent: "center"
      }}>
        {game.board.map((cell, i) => {
          const isWinCell = game.win_line?.includes(i);
          const canClick = !cell && isMyTurn;
          return (
            <button key={i} onClick={() => makeMove(i)}
              style={{
                aspectRatio: "1",
                background: isWinCell
                  ? "rgba(124,92,252,0.25)"
                  : cell ? "var(--card2)" : "var(--card)",
                border: `2px solid ${isWinCell ? "var(--accent)" : canClick ? "rgba(124,92,252,0.3)" : "var(--border)"}`,
                borderRadius: "var(--radius)",
                fontSize: 36, cursor: canClick ? "pointer" : "default",
                display: "flex", alignItems: "center", justifyContent: "center",
                transition: "all 0.15s",
                transform: isWinCell ? "scale(1.05)" : "scale(1)",
                boxShadow: isWinCell ? "0 0 20px rgba(124,92,252,0.4)" : "none",
                animation: cell ? "pop 0.3s cubic-bezier(0.34,1.56,0.64,1)" : "none",
              }}
              onMouseEnter={e => { if (canClick) e.currentTarget.style.background = "var(--card2)"; }}
              onMouseLeave={e => { if (canClick) e.currentTarget.style.background = "var(--card)"; }}
            >
              {cell}
            </button>
          );
        })}
      </div>

      {/* Waiting state */}
      {game.status === "waiting" && (
        <div style={{ marginTop: 24, textAlign: "center" }}>
          <p style={{ color: "var(--text2)", fontSize: 13, marginBottom: 12 }}>
            Отправь этот код другу:
          </p>
          <div style={{
            fontFamily: "Unbounded", fontSize: 28, letterSpacing: 6,
            padding: "12px 24px", background: "var(--card2)",
            border: "1px solid var(--border)", borderRadius: "var(--radius)",
            display: "inline-block"
          }}>{code}</div>
          <button className="btn btn-primary btn-block" style={{ marginTop: 12 }} onClick={copyCode}>
            {copied ? "✓ Скопировано!" : "📋 Копировать код"}
          </button>
        </div>
      )}

      {/* Finished state */}
      {game.status === "finished" && (
        <div style={{ marginTop: 24, display: "flex", flexDirection: "column", gap: 10 }}>
          <button className="btn btn-primary btn-lg btn-block" onClick={() => navigate("/")}>
            🎮 Новая игра
          </button>
          <button className="btn btn-secondary btn-block" onClick={() => navigate("/profile")}>
            👤 Профиль
          </button>
        </div>
      )}
    </div>
  );
}
